
/**
 * @fileOverview Shërbimi për kërkimin e adresave në Kosovë duke përdorur Nominatim/Photon.
 * Optimizuar për kërkim "fuzzy" që pranon gabime drejtshkrimore dhe emra të pjesshëm.
 */

export interface SearchResult {
  name: string;
  lat: number;
  lng: number;
  displayName: string;
}

/**
 * Normalizon tekstin për kërkim më tolerant (p.sh. Ç -> C, Ë -> E).
 */
function normalizeQuery(query: string): string {
  return query
    .toLowerCase()
    .replace(/ç/g, 'c')
    .replace(/ë/g, 'e')
    .replace(/q/g, 'k') // Ndonjëherë përdoret Q për K në emra lokalesh
    .trim();
}

/**
 * Kërkon lokacione në Kosovë duke përdorur Photon API (bazuar në OSM).
 * Photon është shumë më i mirë për kërkime "fuzzy" sesa Nominatim i pastër.
 */
export async function searchLocations(query: string): Promise<SearchResult[]> {
  if (!query || query.trim().length < 2) return [];

  const cleanedQuery = normalizeQuery(query);
  
  try {
    // Bounding Box për Kosovën: [min_lon, min_lat, max_lon, max_lat]
    const kosovoBbox = "20.01,41.85,21.79,43.27";
    
    // Photon API me bias lokacionin e Kosovës
    const url = `https://photon.komoot.io/api/?q=${encodeURIComponent(cleanedQuery)}&bbox=${kosovoBbox}&limit=8&lat=42.6629&lon=21.1655`;
    
    const response = await fetch(url);
    const data = await response.json();

    if (!data || !data.features || data.features.length === 0) {
      // Fallback në Nominatim nëse Photon nuk jep asgjë (me kërkim më strikt)
      const nomUrl = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(query + " Kosovo")}&format=json&limit=5`;
      const nomRes = await fetch(nomUrl);
      const nomData = await nomRes.json();
      
      return nomData.map((item: any) => ({
        name: item.display_name.split(',')[0],
        lat: parseFloat(item.lat),
        lng: parseFloat(item.lon),
        displayName: item.display_name
      }));
    }

    return data.features.map((feature: any) => {
      const p = feature.properties;
      const coords = feature.geometry.coordinates;
      
      const mainName = p.name || p.street || p.district || p.city || "Lokacion";
      
      const parts = [];
      if (p.district) parts.push(p.district);
      if (p.city) parts.push(p.city);
      if (p.state && p.state !== p.city) parts.push(p.state);
      
      const fullDisplayName = parts.length > 0 ? `${mainName} (${parts.join(", ")})` : mainName;

      return {
        name: mainName,
        lat: coords[1],
        lng: coords[0],
        displayName: fullDisplayName
      };
    });
  } catch (error) {
    console.error("Kërkimi dështoi:", error);
    return [];
  }
}
