
"use client"

import { useState, useEffect } from "react";
import dynamic from "next/dynamic";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Search, Navigation, Loader2, MapPin, Play, Target, X } from "lucide-react";
import { useFirestore, useCollection, useMemoFirebase } from "@/firebase";
import { collection, query, orderBy } from "firebase/firestore";
import { useDriving } from "@/context/driving-context";
import { calculateRoutes } from "@/services/navigation/routeService";
import { searchLocations, SearchResult } from "@/services/navigation/geocodingService";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";

const DriveRankMap = dynamic(() => import("@/components/map/DriveRankMap"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-zinc-950 flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-accent" /></div>
});

export default function NavigationPage() {
  const { 
    currentCoords, heading,
    destination, routeData, availableRoutes, isNavigating,
    setDestination, setRouteData, setAvailableRoutes, setIsNavigating, clearNavigation
  } = useDriving();
  
  const db = useFirestore();
  const { toast } = useToast();
  
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<SearchResult[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [forceCenter, setForceCenter] = useState(0);

  const radarQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(collection(db, "radar_reports"), orderBy("createdAt", "desc"));
  }, [db]);
  const { data: alerts } = useCollection(radarQuery);

  // Sistemi i kërkimit Fuzzy (Photon API)
  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.trim().length >= 2) {
        setIsSearching(true);
        try {
          const results = await searchLocations(searchQuery);
          setSearchResults(results);
        } catch (e) {
          console.error("Search failed:", e);
        } finally {
          setIsSearching(false);
        }
      } else {
        setSearchResults([]);
      }
    }, 400);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  const handleSelectDestination = async (result: SearchResult) => {
    setDestination(result);
    setSearchQuery("");
    setSearchResults([]);
    
    if (!currentCoords) {
      toast({ variant: "destructive", title: "GPS 📍", description: "Lejoni qasjen në lokacion." });
      return;
    }

    const routes = await calculateRoutes(currentCoords, { lat: result.lat, lng: result.lng });
    if (routes.length > 0) {
      setAvailableRoutes(routes);
      setRouteData(routes[0]);
      toast({ title: "RRUGA U GJET 🏁", description: `Shtegu drejt ${result.name}` });
    } else {
      toast({ variant: "destructive", title: "GABIM ❌", description: "Nuk u gjet asnjë rrugë." });
    }
  };

  const handleStartNav = () => {
    if (!routeData) return;
    setIsNavigating(true);
    toast({ title: "NAVIGIMI FILLOI 🔥" });
  };

  const handleStopNav = () => {
    setIsNavigating(false);
    clearNavigation();
  };

  const handleClear = () => {
    clearNavigation();
    setSearchQuery("");
    setSearchResults([]);
  };

  return (
    <div className="flex flex-col h-screen bg-black relative overflow-hidden">
      {/* Map Layer */}
      <div className="absolute inset-0 z-0">
        <DriveRankMap 
          userLocation={currentCoords} 
          heading={heading}
          route={routeData?.coordinates || null} 
          alerts={alerts || []}
          destination={destination}
          isNavigating={isNavigating}
          forceCenter={forceCenter}
        />
      </div>

      {/* Interface e Kërkimit */}
      <div className="absolute top-12 left-4 right-4 z-20 space-y-2 pointer-events-none">
        {!isNavigating ? (
          <div className="relative pointer-events-auto">
            <Card className="glass-card p-3 rounded-2xl border-white/10 shadow-2xl flex items-center gap-3 bg-zinc-950/90 backdrop-blur-3xl">
              <Search className="w-5 h-5 text-accent shrink-0" />
              <Input 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Kërko rrugë, qytet..."
                className="bg-transparent border-none h-11 p-0 text-white placeholder:text-zinc-500 focus-visible:ring-0 font-black italic uppercase text-[16px]" 
              />
              {isSearching && <Loader2 className="w-4 h-4 animate-spin text-accent" />}
              {(searchQuery || destination) && (
                <button onClick={handleClear} className="text-zinc-500 hover:text-white p-1">
                  <X className="w-5 h-5" />
                </button>
              )}
            </Card>

            {/* Sugjerimet e kërkimit */}
            {searchResults.length > 0 && (
              <Card className="mt-2 glass-card border-white/10 rounded-2xl shadow-2xl overflow-hidden max-h-[350px] overflow-y-auto no-scrollbar bg-zinc-950/98 relative z-30">
                {searchResults.map((result, idx) => (
                  <button 
                    key={idx}
                    onClick={() => handleSelectDestination(result)}
                    className="w-full p-4 flex items-center gap-4 hover:bg-white/10 border-b border-white/5 last:border-none text-left active:bg-accent/20 transition-colors"
                  >
                    <div className="w-10 h-10 rounded-xl bg-accent/10 flex items-center justify-center shrink-0 border border-accent/20">
                      <MapPin className="w-5 h-5 text-accent" />
                    </div>
                    <div className="flex flex-col min-w-0">
                      <span className="text-sm font-black text-white uppercase italic truncate">{result.name}</span>
                      <span className="text-[9px] font-bold text-zinc-500 uppercase truncate mt-0.5">{result.displayName}</span>
                    </div>
                  </button>
                ))}
              </Card>
            )}
          </div>
        ) : (
          <Card className="glass-card p-5 rounded-[2.5rem] border-red-500/20 shadow-2xl flex items-center justify-between bg-zinc-950/95 backdrop-blur-3xl pointer-events-auto">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-red-600 rounded-2xl flex items-center justify-center animate-pulse shadow-[0_0_20px_rgba(220,38,38,0.5)]">
                <Navigation className="w-7 h-7 text-white" />
              </div>
              <div className="flex flex-col">
                <span className="text-[9px] font-black text-red-500 uppercase tracking-widest">NAVIGIMI AKTIV</span>
                <span className="text-sm font-black text-white uppercase italic truncate max-w-[150px]">{destination?.name}</span>
              </div>
            </div>
            <Button onClick={handleStopNav} variant="destructive" className="rounded-2xl h-11 px-5 font-black uppercase text-[10px]">
              STOP
            </Button>
          </Card>
        )}
      </div>

      {/* Butoni i Lokacionit */}
      <div className="absolute bottom-32 right-4 z-20">
        <Button 
          onClick={() => setForceCenter(prev => prev + 1)}
          className="w-14 h-14 rounded-2xl bg-zinc-950/90 border border-white/10 text-white shadow-2xl flex items-center justify-center active:scale-95 transition-all"
        >
          <Target className="w-7 h-7 text-accent" />
        </Button>
      </div>

      {/* Rrugët Alternative */}
      {routeData && !isNavigating && (
        <div className="absolute bottom-24 left-4 right-4 z-20 space-y-3 animate-in slide-in-from-bottom-5 duration-500">
          <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
            {availableRoutes.map((route, idx) => (
              <Card 
                key={idx}
                onClick={() => setRouteData(route)}
                className={cn(
                  "flex-shrink-0 p-3 rounded-xl border transition-all cursor-pointer min-w-[120px] shadow-xl",
                  routeData === route ? "bg-accent/20 border-accent shadow-accent/10" : "bg-zinc-950/90 border-white/10"
                )}
              >
                <div className="flex flex-col">
                  <span className="text-[7px] font-black uppercase tracking-widest text-muted-foreground mb-0.5">
                    {idx === 0 ? "E SHPEJTË 🔥" : "ALTERNATIVE"}
                  </span>
                  <span className="text-sm font-black text-white italic">
                    {Math.round(route.duration / 60)} MIN
                  </span>
                  <span className="text-[9px] font-bold text-accent">
                    {(route.distance / 1000).toFixed(1)} KM
                  </span>
                </div>
              </Card>
            ))}
          </div>

          <Card className="glass-card p-4 rounded-[2rem] border-accent/20 shadow-2xl bg-zinc-950/95">
            <div className="flex gap-2">
              <Button onClick={handleClear} variant="outline" className="flex-1 h-12 rounded-xl font-black text-[10px] uppercase border-white/10 text-zinc-500 hover:text-white">
                ANULO
              </Button>
              <Button onClick={handleStartNav} className="flex-[2] h-12 bg-accent hover:bg-accent/90 text-background font-black text-base uppercase italic rounded-xl shadow-lg">
                NISU TANI <Play className="w-5 h-5 ml-2 fill-current" />
              </Button>
            </div>
          </Card>
        </div>
      )}

      <BottomNav />
    </div>
  );
}
